type tProxyReq = (isWrite: bool, key: int, value: int, callerCache: machine, podId: int);
type tInFlight = (isWrite: bool, key: int, callerCache: machine, podId: int);
type tWriteQEntry = (client: machine, value: int);

event eProxyPump;

machine StorageProxy {
  var db: machine;
  var pending: seq[tProxyReq];
  var inflight: seq[tInFlight];

  start state Init {
    entry (p: (db: machine)) {
      db = p.db;
      goto Pumping;
    }
  }

  state Pumping {
    on eStorageRead do (req: (caller: machine, key: int, podId: int)) {
      var r: tProxyReq;
      r = (isWrite = false, key = req.key, value = 0, callerCache = req.caller, podId = req.podId);
      pending += (sizeof(pending), r);
      announce eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = false, pending = sizeof(pending));
      send this, eProxyPump;
    }

    on eStorageWrite do (req: (caller: machine, key: int, value: int, podId: int)) {
      var r: tProxyReq;
      r = (isWrite = true, key = req.key, value = req.value, callerCache = req.caller, podId = req.podId);
      pending += (sizeof(pending), r);
      announce eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = true, pending = sizeof(pending));
      send this, eProxyPump;
    }

    on eProxyPump do {
      var n: int;
      var idx: int;
      var r: tProxyReq;
      var f: tInFlight;

      n = sizeof(pending);
      if (n == 0) {
        return;
      }

      if ($) {
        announce eMonitorProxyHold, (pending = n);
      } else {
        idx = choose(n);
        r = pending[idx];
        pending -= (idx);

        announce eMonitorProxyForward, (key = r.key, podId = r.podId, isWrite = r.isWrite, pending = sizeof(pending));

        if (r.isWrite) {
          send db, eStorageWrite, (caller = this, key = r.key, value = r.value, podId = r.podId);
        } else {
          send db, eStorageRead, (caller = this, key = r.key, podId = r.podId);
        }

        f = (isWrite = r.isWrite, key = r.key, callerCache = r.callerCache, podId = r.podId);
        inflight += (sizeof(inflight), f);
      }

      send this, eProxyPump;
    }

    on eStorageReadResp do (resp: (key: int, value: int)) {
      var i: int;
      var found: bool;
      var f: tInFlight;

      i = 0;
      found = false;
      while (i < sizeof(inflight)) {
        if (!inflight[i].isWrite && inflight[i].key == resp.key && !found) {
          f = inflight[i];
          inflight -= (i);
          found = true;
        } else {
          i = i + 1;
        }
      }

      if (found) {
        announce eMonitorProxyResponseDelivered, (key = resp.key, podId = f.podId, isWrite = false);
        send f.callerCache, eStorageReadResp, (key = resp.key, value = resp.value);
      }

      send this, eProxyPump;
    }

    on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
      var i: int;
      var found: bool;
      var f: tInFlight;

      i = 0;
      found = false;
      while (i < sizeof(inflight)) {
        if (inflight[i].isWrite && inflight[i].key == resp.key && !found) {
          f = inflight[i];
          inflight -= (i);
          found = true;
        } else {
          i = i + 1;
        }
      }

      if (found) {
        announce eMonitorProxyResponseDelivered, (key = resp.key, podId = f.podId, isWrite = true);
        send f.callerCache, eStorageWriteResp, (key = resp.key, success = resp.success, value = resp.value);
      }

      send this, eProxyPump;
    }
  }
}

machine CacheNode {
  var proxy: machine;
  var podId: int;

  var cache: map[int, int];
  var waitingReads: map[int, seq[machine]];
  var writeQueues: map[int, seq[tWriteQEntry]];

  start state Init {
    entry (p: (proxy: machine, podId: int)) {
      proxy = p.proxy;
      podId = p.podId;
      cache = default(map[int, int]);
      waitingReads = default(map[int, seq[machine]]);
      writeQueues = default(map[int, seq[tWriteQEntry]]);
      goto Ready;
    }
  }

  state Ready {
    on eClientRead do (req: (client: machine, key: int)) {
      var s: seq[machine];
      if (req.key in waitingReads) {
        s = waitingReads[req.key];
        s += (sizeof(s), req.client);
        waitingReads[req.key] = s;
      } else {
        s = default(seq[machine]);
        s += (0, req.client);
        waitingReads[req.key] = s;
        announce eMonitorProxyRequestIssued, (key = req.key, podId = podId, isWrite = false);
        send proxy, eStorageRead, (caller = this, key = req.key, podId = podId);
      }
    }

    on eStorageReadResp do (resp: (key: int, value: int)) {
      var clients: seq[machine];
      var i: int;

      cache[resp.key] = resp.value;

      if (resp.key in waitingReads) {
        clients = waitingReads[resp.key];
        i = 0;
        while (i < sizeof(clients)) {
          send clients[i], eReadResp, (key = resp.key, value = resp.value, fromCache = false);
          i = i + 1;
        }
        waitingReads -= (resp.key);
      }
    }

    on eClientWrite do (w: (client: machine, key: int, value: int)) {
      var q: seq[tWriteQEntry];
      var firstSend: bool;
      firstSend = false;

      if (w.key in writeQueues) {
        q = writeQueues[w.key];
      } else {
        q = default(seq[tWriteQEntry]);
        firstSend = true;
      }

      q += (sizeof(q), (client = w.client, value = w.value));
      writeQueues[w.key] = q;

      if (sizeof(q) == 1) {
        announce eMonitorProxyRequestIssued, (key = w.key, podId = podId, isWrite = true);
        send proxy, eStorageWrite, (caller = this, key = w.key, value = w.value, podId = podId);
      }
    }

    on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
      var q: seq[tWriteQEntry];
      var entry: tWriteQEntry;

      if (resp.key in writeQueues) {
        q = writeQueues[resp.key];

        if (sizeof(q) > 0) {
          entry = q[0];
          send entry.client, eWriteResp, (key = resp.key, success = resp.success);

          if (resp.success) {
            cache[resp.key] = resp.value;
          }

          q -= (0);
          if (sizeof(q) > 0) {
            writeQueues[resp.key] = q;
            announce eMonitorProxyRequestIssued, (key = resp.key, podId = podId, isWrite = true);
            send proxy, eStorageWrite, (caller = this, key = resp.key, value = q[0].value, podId = podId);
          } else {
            writeQueues -= (resp.key);
          }
        }
      }
    }
  }
}
